import{_ as e,o as t,c as l,a2 as r}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"Cloudflare CDN 加速 GitHub Pages","description":"","frontmatter":{},"headers":[],"relativePath":"reference/Cloudflare加速教程.md","filePath":"reference/Cloudflare加速教程.md","lastUpdated":1780998639000}'),o={name:"reference/Cloudflare加速教程.md"};function s(d,a,n,i,h,c){return t(),l("div",null,[...a[0]||(a[0]=[r(`<h1 id="cloudflare-cdn-加速-github-pages" tabindex="-1">Cloudflare CDN 加速 GitHub Pages <a class="header-anchor" href="#cloudflare-cdn-加速-github-pages" aria-label="Permalink to &quot;Cloudflare CDN 加速 GitHub Pages&quot;">​</a></h1><nav class="table-of-contents"><ul><li><a href="#架构说明">架构说明</a></li><li><a href="#一、注册-cloudflare">一、注册 Cloudflare</a></li><li><a href="#二、修改-dns-托管">二、修改 DNS 托管</a></li><li><a href="#三、配置-dns-记录">三、配置 DNS 记录</a></li><li><a href="#四、ssl-tls-设置">四、SSL/TLS 设置</a></li><li><a href="#五、缓存规则">五、缓存规则</a></li><li><a href="#六、验证">六、验证</a></li><li><a href="#相关链接">相关链接</a></li></ul></nav><h2 id="架构说明" tabindex="-1">架构说明 <a class="header-anchor" href="#架构说明" aria-label="Permalink to &quot;架构说明&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户(国内) → Cloudflare 边缘(香港/新加坡) → GitHub Pages(美国)</span></span>
<span class="line"><span>               ↑ 静态文件缓存到这里，不用每次跨国</span></span></code></pre></div><p>备案前无法用国内 CDN，Cloudflare 的亚洲边缘节点是最优解。</p><hr><h2 id="一、注册-cloudflare" tabindex="-1">一、注册 Cloudflare <a class="header-anchor" href="#一、注册-cloudflare" aria-label="Permalink to &quot;一、注册 Cloudflare&quot;">​</a></h2><ol><li>打开 <a href="https://www.cloudflare.com/" target="_blank" rel="noreferrer">cloudflare.com</a></li><li>注册账号 → <strong>Add a site</strong> → 输入 <code>yyywork.top</code></li><li>选 <strong>Free</strong> 套餐 → Continue</li></ol><hr><h2 id="二、修改-dns-托管" tabindex="-1">二、修改 DNS 托管 <a class="header-anchor" href="#二、修改-dns-托管" aria-label="Permalink to &quot;二、修改 DNS 托管&quot;">​</a></h2><p>Cloudflare 会给你两个<strong>新的 NS 服务器地址</strong>，类似：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>alice.ns.cloudflare.com</span></span>
<span class="line"><span>bob.ns.cloudflare.com</span></span></code></pre></div><p>去<strong>阿里云域名控制台</strong> → 找到 <code>yyywork.top</code> → <strong>DNS 修改</strong> → <strong>修改 DNS 服务器</strong>，把原来的阿里云 DNS 替换成 Cloudflare 给的两个地址。</p><blockquote><p>⚠️ NS 修改后全球生效需要 0-48 小时，通常几小时内完成。期间网站不会中断。</p></blockquote><hr><h2 id="三、配置-dns-记录" tabindex="-1">三、配置 DNS 记录 <a class="header-anchor" href="#三、配置-dns-记录" aria-label="Permalink to &quot;三、配置 DNS 记录&quot;">​</a></h2><p>NS 生效后，在 Cloudflare 控制台 → <code>yyywork.top</code> → <strong>DNS</strong> → <strong>Records</strong>：</p><table tabindex="0"><thead><tr><th>类型</th><th>名称</th><th>目标</th><th>代理状态</th></tr></thead><tbody><tr><td>CNAME</td><td><code>www</code></td><td><code>yyywork1209.github.io</code></td><td>🟠 橙色云朵（已代理）</td></tr></tbody></table><blockquote><p>🟠 橙色云朵 = Cloudflare 代理流量，CDN 生效<br> ⬜ 灰色云朵 = 仅 DNS 解析，CDN 不生效</p></blockquote><hr><h2 id="四、ssl-tls-设置" tabindex="-1">四、SSL/TLS 设置 <a class="header-anchor" href="#四、ssl-tls-设置" aria-label="Permalink to &quot;四、SSL/TLS 设置&quot;">​</a></h2><p>Cloudflare → <code>yyywork.top</code> → <strong>SSL/TLS</strong> → Overview：</p><table tabindex="0"><thead><tr><th>配置</th><th>值</th></tr></thead><tbody><tr><td>SSL/TLS 加密模式</td><td><strong>Full</strong></td></tr><tr><td>Always Use HTTPS</td><td>✅ 开启</td></tr></tbody></table><p>选 <strong>Full</strong> 而不是 Flexible，因为 GitHub Pages 本身支持 HTTPS。</p><hr><h2 id="五、缓存规则" tabindex="-1">五、缓存规则 <a class="header-anchor" href="#五、缓存规则" aria-label="Permalink to &quot;五、缓存规则&quot;">​</a></h2><p>Cloudflare → <strong>Caching</strong> → <strong>Cache Rules</strong> → Create rule：</p><table tabindex="0"><thead><tr><th>条件</th><th>设置</th></tr></thead><tbody><tr><td>URI path 包含 <code>/assets/</code></td><td><strong>Cache: Eligible for cache</strong>，Edge TTL: <strong>1 month</strong></td></tr></tbody></table><p>VitePress 打包后的 JS/CSS 文件名带 hash，永远不会变，缓存一个月没问题。</p><p>HTML 文件 Cloudflare 默认不缓存，保持即可——不需要额外配置。</p><hr><h2 id="六、验证" tabindex="-1">六、验证 <a class="header-anchor" href="#六、验证" aria-label="Permalink to &quot;六、验证&quot;">​</a></h2><p>全部配完后：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://www.yyywork.top</span></span></code></pre></div><p>响应头中出现 <code>server: cloudflare</code> 即表示 CDN 生效。</p><hr><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="https://developers.cloudflare.com/" target="_blank" rel="noreferrer">Cloudflare 官方文档</a></li><li><a href="https://docs.github.com/en/pages/configuring-a-custom-domain-for-your-github-pages-site" target="_blank" rel="noreferrer">GitHub Pages 自定义域名</a></li></ul>`,38)])])}const g=e(o,[["render",s]]);export{u as __pageData,g as default};
